import { useEffect, useState } from "react";

export const useRemoteForm = (key: string) => {
  const [pageForm, setPageForm] = useState<string | null>(null);
  const [formData, setFormData] = useState<any>(null);

  useEffect(() => {

    const run = async () => {
      try {
        // 1️⃣ fetch mapping JSON
        const res = await fetch(
          "https://mtcmarketing.github.io/plugin--remote-content--vien-phat-hoc-v3/forms/forms.json"
        );

        console.log(res)
        const data : any = await res.json();

        console.log("STEP 1 - forms.json:", data);

        // 2️⃣ extract value by key
        const found = data[key];

        console.log(`STEP 2 - value for "${key}":`, found);

        setPageForm(found);

        if (!found) return;

        // 3️⃣ fetch actual form JSON
        const res2 = await fetch(
          `https://mtcmarketing.github.io/plugin--remote-content--vien-phat-hoc-v3/forms/${found}.json?v=${Date.now()}`
        );

        const data2 = await res2.json();

        console.log("STEP 3 - final form JSON:", data2);

        setFormData(data2);
      } catch (err) {
        console.error("ERROR:", err);
      }
    };

    run();
  }, [key]);

  return {
    pageForm,
    formData,
  };
};